using Microsoft.EntityFrameworkCore;

// EF Core 9 Cosmos DB fixes for existing documents:
// 1. Discriminator property renamed from "Discriminator" to "$type" — restore old name
// 2. id property no longer contains discriminator — preserve old compound format
// 3. Sync I/O (ToList, SaveChanges) now throws — use async equivalents

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: Preserve "Discriminator" property name for existing documents
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: Keep old compound id format ("Session|<key>") so existing docs are accessible
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = default!;
    public string Title { get; set; } = default!;
}

// Fix 3: Sync I/O example — before/after
class CosmosQueryService
{
    // BEFORE (EF Core 8 — now throws in EF Core 9):
    //   var sessions = db.Sessions.ToList();
    //   db.SaveChanges();

    // AFTER (EF Core 9 — async required):
    async Task<List<Session>> GetSessionsAsync(CosmosDbContext db)
    {
        return await db.Sessions.ToListAsync();
    }

    async Task SaveAsync(CosmosDbContext db)
    {
        await db.SaveChangesAsync();
    }
}

